import{_ as e,o as i,c as t,ag as n}from"./chunks/framework.DTiDeF2Q.js";const c=JSON.parse('{"title":"Alias Interaktif | Dotfiles (ID)","titleTemplate":":title","description":"Alias Interaktif adalah koleksi alias yang memungkinkan Anda berinteraksi lebih interaktif dengan shell atau terminal.","frontmatter":{"title":"Alias Interaktif | Dotfiles","description":"Alias Interaktif adalah koleksi alias yang memungkinkan Anda berinteraksi lebih interaktif dengan shell atau terminal.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Interaktif preview","canonical":"/id/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Interaktif","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Interaktif - Dotfiles (ID)","permalink":"/id/aliases/interactive/","meta":[{"name":"keywords","content":"alias, bash, cp, interaktif, linux, ln, macos, mv, rm, shell, terminal, windows"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias Interaktif adalah koleksi alias yang memungkinkan Anda berinteraksi lebih interaktif dengan shell atau terminal."},{"name":"twitter:title","content":"Alias Interaktif - Dotfiles (ID)"},{"name":"og:title","content":"Alias Interaktif - Dotfiles (ID)"},{"name":"og:description","content":"Alias Interaktif adalah koleksi alias yang memungkinkan Anda berinteraksi lebih interaktif dengan shell atau terminal."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/interactive/index.md","filePath":"id/aliases/interactive/index.md","lastUpdated":1773010926000}'),r={name:"id/aliases/interactive/index.md"};function l(s,a,o,d,k,u){return i(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="alias-interaktif" tabindex="-1">Alias Interaktif <a class="header-anchor" href="#alias-interaktif" aria-label="Permalink to &quot;Alias Interaktif&quot;">​</a></h1><p>Kelola alias interaktif. Bagian dari konfigurasi <strong>Universal Dotfiles</strong>.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias ini didefinisikan di <code>interactive.aliases.sh</code> dan dimuat secara otomatis oleh <code>chezmoi</code>.</p><h2 id="alias" tabindex="-1">Alias <a class="header-anchor" href="#alias" aria-label="Permalink to &quot;Alias&quot;">​</a></h2><p>Kode ini menyediakan set alias interaktif untuk operasi command line umum. Alias dirancang untuk menyederhanakan dan meningkatkan pengalaman pengguna dengan menambahkan prompt interaktif sebelum menjalankan operasi yang berpotensi destruktif.</p><ul><li><code>cp</code> Salin file dan direktori secara interaktif (konfirmasi sebelum overwrite), tampilkan output verbose.</li><li><code>del</code> Hapus file atau direktori secara interaktif (konfirmasi sebelum setiap penghapusan), tampilkan output verbose secara rekursif.</li><li><code>ln</code> Buat symlink secara interaktif (konfirmasi sebelum overwrite), tampilkan output verbose.</li><li><code>mv</code> Pindahkan atau ganti nama file atau direktori secara interaktif (konfirmasi sebelum overwrite), tampilkan output verbose.</li><li><code>rm</code> Hapus file atau direktori secara interaktif (konfirmasi sebelum setiap penghapusan), tampilkan output verbose.</li><li><code>zap</code> Alias untuk &#39;rm&#39;, hapus file atau direktori secara interaktif, tampilkan output verbose.</li></ul><h3 id="alias-operasi-trash" tabindex="-1">Alias Operasi Trash <a class="header-anchor" href="#alias-operasi-trash" aria-label="Permalink to &quot;Alias Operasi Trash&quot;">​</a></h3><ul><li><code>bin</code> Paksa hapus secara rekursif semua file di direktori Trash (user&#39;s .Trash).</li><li><code>chmod</code> Ubah izin file atau direktori dengan output verbose.</li><li><code>chown</code> Ubah pemilik dan grup file atau direktori dengan output verbose.</li><li><code>diff</code> Bandingkan dan tampilkan perbedaan antara dua file dalam format unified.</li><li><code>grep</code> Cari pola dalam file atau output, tampilkan nomor baris dan pencarian case-insensitive.</li><li><code>mkdir</code> Buat direktori baru, buat direktori parent jika perlu dengan output verbose.</li></ul>',9)])])}const p=e(r,[["render",l]]);export{c as __pageData,p as default};
